import org.intellij.lang.annotations.Language
import org.junit.jupiter.api.Test
import kotlin.test.assertEquals

class TemplateManagerHashFilenameTest {

    @Test
    fun `parseSourcesToFileScheme - filenames containing hash characters`() {
        val mediaDir = "storage/emulated/0/AnkiDroid/collection.media"

        @Language("HTML")
        val content = """<img src="hash#image.png">"""

        val result = parseSourcesToFileScheme(content, mediaDir)
        val expected = """<img src="file:///$mediaDir/hash%23image.png">"""

        assertEquals(expected, result)
    }
}
